SELECT r.*, ste.site_nm AS site_nm, ord.member_nm AS order_nm, cla.member_nm AS claim_nm, cd_rt.code_label AS refund_type_cd_nm, cd_rs.code_label AS refund_status_cd_nm, cd_cf.code_label AS fault_type_cd_nm FROM od_refund r LEFT JOIN sy_site ste ON ste.site_id = r.site_id LEFT JOIN od_order ord ON ord.order_id = r.order_id LEFT JOIN od_claim cla ON cla.claim_id = r.claim_id LEFT JOIN sy_code cd_rt ON cd_rt.code_grp = 'REFUND_TYPE' AND cd_rt.code_value = r.refund_type_cd LEFT JOIN sy_code cd_rs ON cd_rs.code_grp = 'REFUND_STATUS' AND cd_rs.code_value = r.refund_status_cd LEFT JOIN sy_code cd_cf ON cd_cf.code_grp = 'CLAIM_FAULT' AND cd_cf.code_value = r.fault_type_cd
ORDER BY r.refund_id ASC ORDER BY r.refund_id DESC ORDER BY r.reg_date ASC ORDER BY r.reg_date DESC ORDER BY r.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT r.*, ste.site_nm AS site_nm, ord.member_nm AS order_nm, cla.member_nm AS claim_nm, cd_rt.code_label AS refund_type_cd_nm, cd_rs.code_label AS refund_status_cd_nm, cd_cf.code_label AS fault_type_cd_nm FROM od_refund r LEFT JOIN sy_site ste ON ste.site_id = r.site_id LEFT JOIN od_order ord ON ord.order_id = r.order_id LEFT JOIN od_claim cla ON cla.claim_id = r.claim_id LEFT JOIN sy_code cd_rt ON cd_rt.code_grp = 'REFUND_TYPE' AND cd_rt.code_value = r.refund_type_cd LEFT JOIN sy_code cd_rs ON cd_rs.code_grp = 'REFUND_STATUS' AND cd_rs.code_value = r.refund_status_cd LEFT JOIN sy_code cd_cf ON cd_cf.code_grp = 'CLAIM_FAULT' AND cd_cf.code_value = r.fault_type_cd
ORDER BY r.refund_id ASC ORDER BY r.refund_id DESC ORDER BY r.reg_date ASC ORDER BY r.reg_date DESC ORDER BY r.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

