site_id = #{siteId}, order_id = #{orderId}, claim_id = #{claimId}, refund_type_cd = #{refundTypeCd}, refund_prod_amt = #{refundProdAmt}, refund_coupon_amt = #{refundCouponAmt}, refund_ship_amt = #{refundShipAmt}, refund_save_amt = #{refundSaveAmt}, refund_cache_amt = #{refundCacheAmt}, total_refund_amt = #{totalRefundAmt}, refund_status_cd = #{refundStatusCd}, refund_status_cd_before = #{refundStatusCdBefore}, refund_req_date = #{refundReqDate}, refund_complt_date = #{refundCompltDate}, fault_type_cd = #{faultTypeCd}, refund_reason = #{refundReason}, memo = #{memo}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE refund_id = #{refundId}
